// ================= ENROLLIFY CREATE WEBINAR FORM =================

import { useEffect, useState } from "react";
import "./CreateWebinar.css";
import { useNavigate } from "react-router-dom";



function CreateWebinar() {

  const navigate = useNavigate();

  const [formData, setFormData] = useState({
    title: "",
    subtitle: "",
    description: "",
    categories: [],
    price: 0,
    webinarDateTime: "",
    durationMinutes: "",
    language: "English",
    maxSeats: "",
    bannerImage: "",
    meetingLink: "",
    status: "published",
  });

  const categoriesList = [
    "Marketing", "Business", "Technology", "Finance",
    "Startup", "Design", "Health", "Education"
  ];

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleCategoryChange = (cat) => {
    if (formData.categories.includes(cat)) {
      setFormData({
        ...formData,
        categories: formData.categories.filter(c => c !== cat)
      });
    } else {
      setFormData({
        ...formData,
        categories: [...formData.categories, cat]
      });
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    const selectedPlan = localStorage.getItem("selectedPlan") || 699;

    // RANDOM TEMPLATE ID (0–8)
    const templateId = Math.floor(Math.random() * 9);

    const finalData = {
      title: formData.title,
      subtitle: formData.subtitle || "",
      description: formData.description,
      bannerImage: formData.bannerImage || "",
      webinarDateTime: formData.webinarDateTime,
      durationMinutes: formData.durationMinutes,
      meetingLink: formData.meetingLink || "",
      categories: formData.categories || [],
      plan: selectedPlan,
      templateId: templateId
    };

    localStorage.setItem("webinarData", JSON.stringify(finalData));
    navigate("/template");
  };

  return (
    <div className="webinar-wrapper">

      <div className="form-card">

        <h1>Create Your Webinar 🎤</h1>

        <form onSubmit={handleSubmit}>

          <div className="grid">
            <input name="title" placeholder="Title *" required onChange={handleChange} />
            <input name="subtitle" placeholder="Subtitle" onChange={handleChange} />
          </div>

          <textarea
            name="description"
            placeholder="Description *"
            required
            onChange={handleChange}
          />

          <h2>Select Categories *</h2>

          <div className="category-grid">
            {categoriesList.map(cat => (
              <div
                key={cat}
                className={`category ${formData.categories.includes(cat) ? "active-cat" : ""}`}
                onClick={() => handleCategoryChange(cat)}
              >
                {cat}
              </div>
            ))}
          </div>

          <div className="grid">
            <input name="price" type="number" placeholder="Price (0 = Free)" onChange={handleChange} />
            <input name="webinarDateTime" type="datetime-local" required onChange={handleChange} />
            <input name="durationMinutes" type="number" placeholder="Duration (Minutes)*" required onChange={handleChange} />
            <input name="maxSeats" type="number" placeholder="Max Seats" onChange={handleChange} />
          </div>

          <div className="grid">
            <input name="language" placeholder="Language" defaultValue="English" onChange={handleChange} />
            <input name="bannerImage" placeholder="Banner Image URL" onChange={handleChange} />
            <input name="meetingLink" placeholder="Meeting Link" onChange={handleChange} />
          </div>

          <div className="toggle">
            <button type="button"
              className={formData.status === "draft" ? "active-btn" : ""}
              onClick={() => setFormData({ ...formData, status: "draft" })}>
              Draft
            </button>
            <button type="button"
              className={formData.status === "published" ? "active-btn" : ""}
              onClick={() => setFormData({ ...formData, status: "published" })}>
              Published
            </button>
          </div>

          <button type="submit">Create Webinar 🚀</button>

        </form>

      </div>
    </div>
  );
}

export default CreateWebinar;

import React, { useState, useEffect } from "react";
import "./TemplatePage.css";

function TemplatePage() {
  const [data, setData] = useState(null);
  const [themeClass, setThemeClass] = useState("theme-default");
  const [themeImage, setThemeImage] = useState("");

  useEffect(() => {
    // Fetch data from localStorage
    const savedData = JSON.parse(localStorage.getItem("webinarData"));

    // Fallback dummy data just in case localStorage is empty during testing
    const defaultData = {
      title: "Social Media Marketing Mastery",
      subtitle: "Unlock the knowledge to scale your business",
      description: "Learn the secrets of the gods of marketing. This comprehensive guide will take you through the fastest ways to grow your audience and protect your brand's reputation online.",
      categories: ["Marketing", "Business", "Finance"],
      webinarDateTime: "03/02/2026 02:30 PM",
      durationMinutes: "120",
      capacity: "100",
      language: "English"
    };

    const webinarData = savedData || defaultData;
    setData(webinarData);

    // Determine Theme Based on First Category
    if (webinarData && webinarData.categories && webinarData.categories.length > 0) {
      const primaryCategory = webinarData.categories[0].toLowerCase();
      
      switch (primaryCategory) {
        case 'marketing':
        case 'business':
          setThemeClass("theme-marketing"); // Green & Blue (like screenshot)
          setThemeImage("https://images.unsplash.com/photo-1557804506-669a67965ba0?ixlib=rb-1.2.1&auto=format&fit=crop&w=600&q=80");
          break;
        case 'finance':
        case 'startup':
          setThemeClass("theme-finance"); // Purple & Gold
          setThemeImage("https://images.unsplash.com/photo-1579532537598-459ecdaf39cc?ixlib=rb-1.2.1&auto=format&fit=crop&w=600&q=80");
          break;
        case 'design':
        case 'technology':
          setThemeClass("theme-design"); // Pink & Orange
          setThemeImage("https://images.unsplash.com/photo-1561070791-2526d30994b5?ixlib=rb-1.2.1&auto=format&fit=crop&w=600&q=80");
          break;
        case 'health':
        case 'education':
          setThemeClass("theme-health"); // Teal & Yellow
          setThemeImage("https://images.unsplash.com/photo-1576091160399-112ba8d25d1d?ixlib=rb-1.2.1&auto=format&fit=crop&w=600&q=80");
          break;
        default:
          setThemeClass("theme-default"); // Standard Blue
          setThemeImage("https://images.unsplash.com/photo-1552664730-d307ca884978?ixlib=rb-1.2.1&auto=format&fit=crop&w=600&q=80");
      }
    } else {
        setThemeClass("theme-default");
        setThemeImage("https://images.unsplash.com/photo-1552664730-d307ca884978?ixlib=rb-1.2.1&auto=format&fit=crop&w=600&q=80");
    }
  }, []);

  if (!data) return <div className="loading">Loading Webinar...</div>;

  // Destructure the data
  const {
    title,
    subtitle,
    description,
    categories = [],
    webinarDateTime,
    durationMinutes,
    capacity,
    language
  } = data;

  // Function to wrap the second half of the title in a highlighted <span>
  const renderHighlightedTitle = (fullTitle) => {
    if (!fullTitle) return null;
    const words = fullTitle.split(" ");
    if (words.length <= 2) {
      return <><span className="highlight-text">{fullTitle}</span></>;
    }
    const midPoint = Math.floor(words.length / 2);
    const firstHalf = words.slice(0, midPoint).join(" ");
    const secondHalf = words.slice(midPoint).join(" ");
    
    return (
      <>
        {firstHalf} <span className="highlight-text">{secondHalf}</span>
      </>
    );
  };

  // Extract Date and Time for the UI
  // Handle both space-separated ("YYYY-MM-DD HH:MM AM") and T-separated ("YYYY-MM-DDTHH:MM") formats
  let datePart = "TBD";
  let timePart = "TBD";
  let ampmPart = "";
  
  if (webinarDateTime) {
    if (webinarDateTime.includes("T")) {
      const parts = webinarDateTime.split("T");
      datePart = parts[0];
      timePart = parts[1];
    } else {
      const parts = webinarDateTime.split(" ");
      datePart = parts[0] || "TBD";
      timePart = parts[1] || "TBD";
      ampmPart = parts[2] || "";
    }
  }

  const formattedTime = timePart !== "TBD" ? `${timePart} ${ampmPart}`.trim() : "TBD";

  return (
    <div className={`premium-webinar-wrapper ${themeClass}`}>
      <div className="premium-webinar-container">
        
        {/* Top Header Badge */}
        <div className="header-badge-container">
          <div className="header-badge">
            <span className="badge-main">Unmute Your Power</span>
            <span className="badge-sub">{durationMinutes}-Minute Workshop Mastery</span>
          </div>
        </div>

        {/* Trust Text & Main Title */}
        <div className="title-section">
          <h4 className="trust-heading">
            <span className="trust-highlight">{capacity}+ Participants</span> Improved Their Skills & Achieved Higher Growth
          </h4>
          
          <h1 className="main-headline">
            Learn how to masterfully execute your strategy to <br/>
            {renderHighlightedTitle(title)}
          </h1>
          
          <p className="main-subheadline">
            {subtitle} - Even if you've been doing the work for years but still feel <strong>overlooked or underestimated</strong>.
          </p>
        </div>

        {/* Content Split: Image vs Details */}
        <div className="content-split">
          
          {/* Left Side: Circular Image */}
          <div className="image-side">
            <div className="circular-image-wrapper">
              <img src={themeImage} alt="Webinar Theme" className="circular-image" />
              
              {/* Floating review card */}
              <div className="floating-card review-card">
                 <div className="stars">★★★★★</div>
                 <span className="review-text">4.9/5 Reviews By {capacity}+</span>
              </div>
            </div>
            <p className="description-paragraph">"{description}"</p>
            <div className="course-categories">
              {categories.map((cat, index) => (
                <span key={index} className="course-cat">{cat}</span>
              ))}
            </div>
          </div>

          {/* Right Side: Workshop Details & CTA */}
          <div className="details-side">
            <h3 className="details-header">Workshop Details</h3>
            
            <div className="details-grid">
              
              <div className="detail-box">
                <div className="detail-icon">📅</div>
                <div className="detail-info">
                  <span className="detail-label">Date</span>
                  <strong className="detail-value">{datePart}</strong>
                </div>
              </div>

              <div className="detail-box">
                <div className="detail-icon">🕒</div>
                <div className="detail-info">
                  <span className="detail-label">Time</span>
                  <strong className="detail-value">{formattedTime}</strong>
                </div>
              </div>

              <div className="detail-box">
                <div className="detail-icon">💻</div>
                <div className="detail-info">
                  <span className="detail-label">Workshop</span>
                  <strong className="detail-value">Zoom / Online</strong>
                </div>
              </div>

              <div className="detail-box">
                <div className="detail-icon">🌍</div>
                <div className="detail-info">
                  <span className="detail-label">Language</span>
                  <strong className="detail-value">{language}</strong>
                </div>
              </div>

            </div>

            <div className="bonus-gift">
              🎁 FREE Bonus: Exclusive Action Guide (₹499 Value)
            </div>

            <button className="premium-cta-btn">
              Register Now for Limited Spots
            </button>
            <p className="registration-end">
              Registrations End Soon!
            </p>
          </div>

        </div>

      </div>
    </div>
  );
}

export default TemplatePage;
